package com.flowledger.supplier.controller; import com.flowledger.supplier.dto.SupplierDtos.*; import com.flowledger.supplier.service.SupplierService; import jakarta.validation.Valid; import org.springframework.data.domain.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.math.*; import java.util.*; @RestController @RequestMapping("/api/v1/suppliers") public class SupplierController {private final SupplierService s;public SupplierController(SupplierService s){this.s=s;}@PostMapping @ResponseStatus(HttpStatus.CREATED) public Response create(@Valid @RequestBody Create d){return s.create(d);}@GetMapping("/{id}") public Response get(@PathVariable UUID id){return s.get(id);}@PutMapping("/{id}") public Response update(@PathVariable UUID id,@Valid @RequestBody Update d){return s.update(id,d);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void archive(@PathVariable UUID id){s.archive(id);}@GetMapping public Page<Response> search(@RequestParam(required=false)String search,@RequestParam(required=false)Boolean archived,Pageable p){return s.search(new Search(search,archived),p);}@GetMapping("/{id}/statement")public Statement statement(@PathVariable UUID id){return s.statement(id);}@GetMapping("/{id}/outstanding")public BigDecimal outstanding(@PathVariable UUID id){return s.outstanding(id);}@GetMapping("/{id}/payments")public List<Object> payments(@PathVariable UUID id){s.get(id);return List.of();}}